import{_ as n,I as o,c as r,o as i,a5 as l,J as s,j as t,a,aB as g}from"./chunks/framework.Dtwt352Q.js";const x=JSON.parse('{"title":"认识 Agent：你的专属团队","description":"OpenCode Agent 就像不同工种的专家，用 Tab 键切换主 Agent，用 @agent名 调用子 Agent，实现高效协作。","frontmatter":{"title":"认识 Agent：你的专属团队","subtitle":"不同专家，不同任务","course":"OpenCode 中文实战课","stage":"第三阶段","lesson":"3.2","duration":"12 分钟","practice":"15 分钟","level":"新手","description":"OpenCode Agent 就像不同工种的专家，用 Tab 键切换主 Agent，用 @agent名 调用子 Agent，实现高效协作。","tags":["Agent","子代理","协作"],"prerequisite":["3.1 Plan vs Build"]},"headers":[],"relativePath":"3-workflow/02-agents.md","filePath":"3-workflow/02-agents.md","lastUpdated":1772014034000}'),c={name:"3-workflow/02-agents.md"};function p(h,e,b,u,A,m){const d=o("AdInArticle");return i(),r("div",null,[e[0]||(e[0]=l('<h1 id="认识-agent-你的专属团队" tabindex="-1">认识 Agent：你的专属团队 <a class="header-anchor" href="#认识-agent-你的专属团队" aria-label="Permalink to “认识 Agent：你的专属团队”">​</a></h1><blockquote><p>💡 <strong>一句话总结</strong>：Agent 就像不同工种的专家，用 <kbd>Tab</kbd> 切换主 Agent，用 <code>@agent名</code> 调用子 Agent。</p></blockquote><h2 id="📝-课程笔记" tabindex="-1">📝 课程笔记 <a class="header-anchor" href="#📝-课程笔记" aria-label="Permalink to “📝 课程笔记”">​</a></h2><p>本课核心知识点整理：</p><p><img src="'+g+'" alt="认识 Agent：你的专属团队学霸笔记" data-zoom-src="/images/3-workflow/agents-notes.jpeg"></p><hr><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to “学完你能做什么”">​</a></h2><ul><li>理解什么是 Agent（主代理 vs 子代理）</li><li>知道内置 Agent 各自擅长什么</li><li>能调用不同 Agent 完成任务</li><li>能在父子会话之间导航</li></ul><hr><hr><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to “你现在的困境”">​</a></h2><ul><li>每次都和同一个 AI 对话，不知道还有其他&quot;专家&quot;可用</li><li>遇到复杂任务，不知道怎么让多个 AI 协作</li><li>听说过 Agent，但不知道具体怎么用</li></ul><hr><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to “什么时候用这一招”">​</a></h2><ul><li>当你需要：让专业的 AI 做专业的事</li><li>而且不想：什么任务都丢给同一个通用 AI</li></ul><hr><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to “🎒 开始前的准备”">​</a></h2><blockquote><p>确保你已经完成以下事项：</p></blockquote><ul><li>[ ] 完成了 <a href="./01-plan-build.html">3.1 Plan vs Build</a></li><li>[ ] 有一个项目目录</li></ul><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to “核心思路”">​</a></h2><h3 id="什么是-agent" tabindex="-1">什么是 Agent <a class="header-anchor" href="#什么是-agent" aria-label="Permalink to “什么是 Agent”">​</a></h3><p>Agent 就像你的 AI 团队成员，每个人有不同的专长：</p><ul><li><strong>Build Agent</strong>：全能开发者，能读写文件、执行命令</li><li><strong>Plan Agent</strong>：规划分析师，主要用于分析代码和提供建议（可写 <code>.opencode/plans/*.md</code> 保存方案）</li><li><strong>Explore Agent</strong>：代码探索者，快速理解代码库结构</li><li><strong>General Agent</strong>：通用助手，擅长复杂研究和多步骤任务</li></ul><h3 id="两种类型" tabindex="-1">两种类型 <a class="header-anchor" href="#两种类型" aria-label="Permalink to “两种类型”">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>调用方式</th></tr></thead><tbody><tr><td><strong>Primary Agent（主代理）</strong></td><td>你直接对话的 Agent（Build、Plan）</td><td><kbd>Tab</kbd> 切换</td></tr><tr><td><strong>Subagent（子代理）</strong></td><td>被主代理自动调用或你手动调用的专家（Explore、General）</td><td><code>@agent名 任务</code></td></tr></tbody></table><h3 id="内置-agent-速览" tabindex="-1">内置 Agent 速览 <a class="header-anchor" href="#内置-agent-速览" aria-label="Permalink to “内置 Agent 速览”">​</a></h3>',27)),s(d),e[1]||(e[1]=l('<table tabindex="0"><thead><tr><th>Agent</th><th>类型</th><th>擅长</th><th>默认权限</th></tr></thead><tbody><tr><td>Build</td><td>Primary</td><td>全能开发（默认主 Agent）</td><td>全能（可读写文件、执行命令）</td></tr><tr><td>Plan</td><td>Primary</td><td>分析代码、规划方案、审查建议</td><td>受限（默认禁止编辑，仅 <code>.opencode/plans/*.md</code> 允许写入）</td></tr><tr><td>Explore</td><td>Subagent</td><td>快速找到文件、搜索代码、回答代码库问题</td><td>只读（可搜索、浏览代码）</td></tr><tr><td>General</td><td>Subagent</td><td>复杂研究、多步骤任务、不确定能否快速找到答案时</td><td>多任务执行（可用 Todo 工具）</td></tr></tbody></table><details class="details custom-block"><summary>🔧 内部 Agent（自动运行，无需手动调用）</summary><p>OpenCode 还有 3 个隐藏的内部 Agent，自动在后台工作：</p><table tabindex="0"><thead><tr><th>Agent</th><th>作用</th><th>触发时机</th></tr></thead><tbody><tr><td><strong>compaction</strong></td><td>上下文压缩</td><td>当对话接近模型上下文限制时，自动压缩历史消息</td></tr><tr><td><strong>title</strong></td><td>会话标题生成</td><td>创建新会话后，自动生成描述性标题</td></tr><tr><td><strong>summary</strong></td><td>会话摘要生成</td><td>压缩会话时，生成摘要替代历史消息</td></tr></tbody></table><p>你不需要直接调用它们，OpenCode 会在需要时自动使用。</p></details><hr><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to “跟我做”">​</a></h2><h3 id="第-1-步-查看当前-agent" tabindex="-1">第 1 步：查看当前 Agent <a class="header-anchor" href="#第-1-步-查看当前-agent" aria-label="Permalink to “第 1 步：查看当前 Agent”">​</a></h3><p><strong>为什么</strong><br> 了解现在是哪个 Agent 在工作。</p><p>看状态栏，会显示当前 Agent 名称（如 <code>Build</code> 或 <code>Plan</code>）。</p><h3 id="第-2-步-用-tab-切换主-agent" tabindex="-1">第 2 步：用 Tab 切换主 Agent <a class="header-anchor" href="#第-2-步-用-tab-切换主-agent" aria-label="Permalink to “第 2 步：用 Tab 切换主 Agent”">​</a></h3><p><strong>为什么</strong><br> 在 Build Agent 和 Plan Agent 之间切换。</p><p>按 <kbd>Tab</kbd> 键切换。</p><h3 id="第-3-步-调用-explore-agent" tabindex="-1">第 3 步：调用 Explore Agent <a class="header-anchor" href="#第-3-步-调用-explore-agent" aria-label="Permalink to “第 3 步：调用 Explore Agent”">​</a></h3><p><strong>为什么</strong><br> 让专业的代码探索 Agent 帮你理解项目。</p><p>输入：</p>',13)),e[2]||(e[2]=t("div",{class:"language-"},[t("button",{title:"Copy Code",class:"copy"}),t("span",{class:"lang"}),t("pre",null,[t("code",{"v-pre":""},"@explore 帮我梳理这个项目的整体结构")])],-1)),e[3]||(e[3]=t("p",null,[t("strong",null,"你应该看到"),a("：Explore Agent 开始工作，分析项目结构")],-1)),e[4]||(e[4]=t("div",{class:"tip custom-block"},[t("p",{class:"custom-block-title"},"💡 Explore 的三种探索深度"),t("p",null,"调用 Explore 时，AI 会根据你的任务描述自动选择探索深度。你也可以在提示词中指定："),t("table",{tabindex:"0"},[t("thead",null,[t("tr",null,[t("th",null,"深度"),t("th",null,"说明"),t("th",null,"适合场景")])]),t("tbody",null,[t("tr",null,[t("td",null,[t("strong",null,"quick")]),t("td",null,"基本搜索，快速定位"),t("td",null,'"找一下 config 文件在哪"')]),t("tr",null,[t("td",null,[t("strong",null,"medium")]),t("td",null,"中等探索，平衡速度和覆盖面"),t("td",null,'"帮我梳理项目结构"')]),t("tr",null,[t("td",null,[t("strong",null,"very thorough")]),t("td",null,"全面分析，跨多个位置和命名约定进行搜索"),t("td",null,'"找出所有安全相关的代码"')])])]),t("p",null,"比如想做一次彻底的探索，可以这样写："),t("div",{class:"language-"},[t("button",{title:"Copy Code",class:"copy"}),t("span",{class:"lang"}),t("pre",null,[t("code",{"v-pre":""},"@explore 彻底分析这个项目的认证和鉴权实现，要非常全面")])]),t("p",null,'AI 看到"彻底""非常全面"这类描述，会自动采用 very thorough 级别。')],-1)),e[5]||(e[5]=l('<div class="tip custom-block"><p class="custom-block-title">💡 子代理会话</p><p>调用子代理后，会创建一个子会话。你可以用 <code>&lt;leader&gt;→</code> 进入子会话，用 <code>&lt;leader&gt;←</code> 返回父会话。（默认 leader 是 <code>Ctrl</code>+<code>X</code>）</p></div><h3 id="第-4-步-调用-general-agent" tabindex="-1">第 4 步：调用 General Agent <a class="header-anchor" href="#第-4-步-调用-general-agent" aria-label="Permalink to “第 4 步：调用 General Agent”">​</a></h3><p><strong>为什么</strong><br> General Agent 擅长复杂研究和多步骤任务。</p><p>输入：</p>',4)),e[6]||(e[6]=t("div",{class:"language-"},[t("button",{title:"Copy Code",class:"copy"}),t("span",{class:"lang"}),t("pre",null,[t("code",{"v-pre":""},"@general 帮我研究 Node.js 和 Python 的性能对比，并输出总结报告")])],-1)),e[7]||(e[7]=t("p",null,[t("strong",null,"你应该看到"),a("：General Agent 并行执行多个研究任务，整合结果")],-1)),e[8]||(e[8]=t("h3",{id:"第-5-步-让主-agent-自动调用子-agent",tabindex:"-1"},[a("第 5 步：让主 Agent 自动调用子 Agent "),t("a",{class:"header-anchor",href:"#第-5-步-让主-agent-自动调用子-agent","aria-label":"Permalink to “第 5 步：让主 Agent 自动调用子 Agent”"},"​")],-1)),e[9]||(e[9]=t("p",null,[t("strong",null,"为什么"),t("br"),a(" 主 Agent 会根据任务描述和 Agent 的 description 自动判断是否需要调用子 Agent。")],-1)),e[10]||(e[10]=t("p",null,"输入一个复杂任务：",-1)),e[11]||(e[11]=t("div",{class:"language-"},[t("button",{title:"Copy Code",class:"copy"}),t("span",{class:"lang"}),t("pre",null,[t("code",{"v-pre":""},"帮我分析这个项目的代码结构，然后添加一个 README.md")])],-1)),e[12]||(e[12]=l('<p><strong>你应该看到</strong>：Build Agent 可能会自动调用 Explore Agent 分析项目结构，然后自己创建 README</p><div class="tip custom-block"><p class="custom-block-title">💡 自动调用规则</p><p>主 Agent 会根据子 Agent 的 <code>description</code> 决定何时调用。例如 Explore 的描述是&quot;快速找到文件、搜索代码&quot;，当任务涉及搜索或探索代码库时就会被调用。</p></div><h3 id="第-5-5-步-查看-agent-列表" tabindex="-1">第 5.5 步：查看 Agent 列表 <a class="header-anchor" href="#第-5-5-步-查看-agent-列表" aria-label="Permalink to “第 5.5 步：查看 Agent 列表”">​</a></h3><p><strong>为什么</strong><br> 了解当前有哪些 Agent 可用。</p><p>按 <code>&lt;leader&gt;a</code> 列出所有 Agent（默认 leader 是 <code>Ctrl</code>+<code>X</code>，即 <code>Ctrl</code>+<code>X</code>+<code>a</code>）</p><p><strong>你应该看到</strong>：</p><ul><li>Primary Agents: build、plan</li><li>Subagents: explore、general</li><li>以及你自定义的 Agent（如果有）</li></ul><p>按 <kbd>Esc</kbd> 退出列表。</p><h3 id="第-6-步-在父子会话间导航" tabindex="-1">第 6 步：在父子会话间导航 <a class="header-anchor" href="#第-6-步-在父子会话间导航" aria-label="Permalink to “第 6 步：在父子会话间导航”">​</a></h3><p><strong>为什么</strong><br> 查看子 Agent 的详细工作过程，或在主会话和子会话之间切换。</p><ul><li>按 <code>&lt;leader&gt;→</code> 进入下一个会话（父 → 子1 → 子2 → ... → 父）</li><li>按 <code>&lt;leader&gt;←</code> 返回上一个会话（父 ← 子1 ← 子2 ← ... ← 父）</li><li>按 <code>&lt;leader&gt;↑</code> 直接跳转到父会话</li></ul><p><strong>会话层级示例</strong>：</p>',12)),e[13]||(e[13]=t("div",{class:"language-"},[t("button",{title:"Copy Code",class:"copy"}),t("span",{class:"lang"}),t("pre",null,[t("code",{"v-pre":""},`主会话 (Build)
  └── 子会话 (Explore)
        └── 孙会话 (General)`)])],-1)),e[14]||(e[14]=l('<p>用导航快捷键可以在多层会话之间自由切换。</p><div class="tip custom-block"><p class="custom-block-title">💡 默认快捷键</p><ul><li><code>leader</code> 键默认是 <code>Ctrl</code>+<code>X</code></li><li><code>&lt;leader&gt;→</code> = <code>Ctrl</code>+<code>X</code>+<code>→</code>（右箭头）</li><li><code>&lt;leader&gt;←</code> = <code>Ctrl</code>+<code>X</code>+<code>←</code>（左箭头）</li><li><code>&lt;leader&gt;↑</code> = <code>Ctrl</code>+<code>X</code>+<code>↑</code>（上箭头）</li></ul></div><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to “检查点 ✅”">​</a></h2><blockquote><p>全部通过才能继续</p></blockquote><ul><li>[ ] 知道当前是哪个 Agent（看状态栏）</li><li>[ ] 能用 <kbd>Tab</kbd> 在 Build 和 Plan 之间切换</li><li>[ ] 能用 <code>@explore</code> 和 <code>@general</code> 调用子 Agent</li><li>[ ] 能用快捷键在父子会话间切换</li></ul><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to “踩坑提醒”">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>原因</th><th>解决</th></tr></thead><tbody><tr><td><code>@agent名</code> 没反应</td><td>Agent 名称拼错了或不是子代理</td><td>检查拼写，内置子代理有 <code>explore</code>、<code>general</code>。主代理（<code>build</code>、<code>plan</code>）只能用 <kbd>Tab</kbd> 切换</td></tr><tr><td>子会话看不到</td><td>没有展开或导航到错误的层级</td><td>用 <code>&lt;leader&gt;→</code> / <code>&lt;leader&gt;←</code> 导航，或者按 <code>&lt;leader&gt;↑</code> 返回父会话</td></tr><tr><td>想切换到 Explore，但 Tab 找不到</td><td><kbd>Tab</kbd> 只能在主代理（Primary Agent）之间切换</td><td>Explore 是子代理（Subagent），只能用 <code>@explore</code> 调用</td></tr><tr><td>子 Agent 被中断后找不到</td><td>会话可能已关闭或导航到错误层级</td><td>按 <code>&lt;leader&gt;↑</code> 返回父会话，然后用 <code>&lt;leader&gt;→</code> 查找</td></tr><tr><td>Plan Agent 提示&quot;是否允许编辑&quot;</td><td>Plan Agent 默认对文件修改和命令执行都设置为 <code>ask</code></td><td>这是正常行为，Plan 是用于分析的，执行操作前会请求批准</td></tr><tr><td>General Agent 没有执行多步任务</td><td>任务描述不够清晰或任务不够复杂</td><td>在提示中明确说明需要执行哪些步骤，或确保任务确实需要多步执行</td></tr></tbody></table><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to “本课小结”">​</a></h2><p>你学会了：</p><ol><li>Agent 是什么（不同专长的 AI 团队成员）</li><li>主代理用 <kbd>Tab</kbd> 切换，子代理用 <code>@agent名</code> 调用</li><li>用快捷键在父子会话间导航</li></ol><div class="tip custom-block"><p class="custom-block-title">📚 深入学习</p><p>想要创建自己的 Agent 或深入了解 Agent 配置？ → 继续阅读 <strong><a href="./../5-advanced/02a-agent-quickstart.html">5.2a Agent 快速入门</a></strong></p></div><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to “下一课预告”">​</a></h2><blockquote><p>下一课我们将学习项目初始化，用 <code>/init</code> 让 AI 更懂你的项目。</p></blockquote>',17))])}const P=n(c,[["render",p]]);export{x as __pageData,P as default};
